frappe.listview_settings['greytHR Sync Log'] = frappe.listview_settings['greytHR Sync Log'] || {};
const _greythr_trigger_sync = (listview) => {
    frappe.confirm(
        'Trigger a fresh pull of all employees from greytHR now?<br><br>This usually takes ~30 seconds. A new Sync Log entry will appear when it starts.',
        () => {
            frappe.call({
                method: 'globex_hr_letters.tasks.pull_employees.run_now',
                callback: (r) => {
                    if (!r.exc) {
                        frappe.show_alert({
                            message: 'Sync started \u2014 refresh in ~30s to see the new Sync Log entry.',
                            indicator: 'green'
                        }, 10);
                        setTimeout(() => listview && listview.refresh(), 30000);
                    }
                }
            });
        }
    );
};
frappe.listview_settings['greytHR Sync Log'].onload = function(listview) {
    const roles = frappe.user_roles || [];
    if (!roles.includes('HR Manager') && !roles.includes('System Manager')) return;
    listview.page.add_inner_button('Sync from greytHR Now', () => _greythr_trigger_sync(listview));
    const params = new URLSearchParams(window.location.search);
    if (params.get('manual_sync') === '1') {
        history.replaceState(null, '', window.location.pathname);
        setTimeout(() => _greythr_trigger_sync(listview), 300);
    }
};

frappe.ui.form.on('Employee', {
    refresh(frm) {
        if (frm.is_new()) return;
        const roles = frappe.user_roles || [];
        if (!roles.includes('HR Manager') && !roles.includes('System Manager')) return;

        frm.add_custom_button('Generate Promotion Letter', () => {
            const d = new frappe.ui.Dialog({
                title: 'Generate Promotion Letter',
                fields: [
                    {fieldname: 'old_designation', label: 'Previous Designation', fieldtype: 'Data', reqd: 1, default: frm.doc.designation || ''},
                    {fieldname: 'new_designation', label: 'New Designation', fieldtype: 'Data', reqd: 1},
                    {fieldname: 'effective_date', label: 'Effective Date', fieldtype: 'Date', reqd: 1, default: frappe.datetime.get_today()},
                    {fieldname: 'notes', label: 'Notes (optional)', fieldtype: 'Small Text'}
                ],
                primary_action_label: 'Generate',
                primary_action: (values) => {
                    frappe.call({
                        method: 'globex_hr_letters.hooks_handlers.employee.send_promotion_letter',
                        args: {
                            employee_name: frm.doc.name,
                            old_designation: values.old_designation,
                            new_designation: values.new_designation,
                            effective_date: values.effective_date,
                            notes: values.notes || ''
                        },
                        callback: (r) => {
                            d.hide();
                            if (!r.exc) {
                                frappe.show_alert({message: 'Promotion Letter generation started — check Employee attachments in ~30s.', indicator: 'green'}, 8);
                            }
                        }
                    });
                }
            });
            d.show();
        }, 'Letters');
    }
});

frappe.ui.form.on('Employee', {
    refresh(frm) {
        if (frm.is_new()) return;
        if (frm.doc.status !== 'Active') return;
        const roles = frappe.user_roles || [];
        if (!roles.includes('HR Manager') && !roles.includes('System Manager')) return;

        frm.add_custom_button('Generate Service Certificate', () => {
            frappe.confirm(
                `Generate Service Certificate for <b>${frm.doc.employee_name}</b>?`,
                () => {
                    frappe.call({
                        method: 'globex_hr_letters.hooks_handlers.employee.send_service_certificate',
                        args: {employee_name: frm.doc.name},
                        callback: (r) => {
                            if (!r.exc) {
                                frappe.show_alert({message: 'Service Certificate generation started — check Employee attachments in ~30s.', indicator: 'green'}, 8);
                            }
                        }
                    });
                }
            );
        }, 'Letters');
    }
});
